/// <reference no-default-lib="true"/>

interface Date {
    toGMTString(): string;
    /**
     * Gets the year of the Date object minus 1900.
     *
     * @returns The year of the Date object minus 1900.
     *
     * @example
     * ```ts
     * const date = new Date(1767077132777); // Year 2025
     * date.getYear(); // 125
     * ```
     */
    getYear(): number;
    /**
     * Sets the year of the Date object to the provided value plus 1900.
     *
     * @param year The year to set minus 1900.
     * @returns A number.
     *
     * @example
     * ```ts
     * const date = new Date(1767077132777); // Year 2025
     * date.setYear(125); // -58191153267223 // Year 2025
     * date.setYear(50); // -599764467223 // Year 1950
     * ```
     */
    setYear(year: number): number;
}

interface Object {
    // hasOwnProperty(v: keyof this): boolean;
    // propertyIsEnumerable(v: keyof this): boolean;
    __defineGetter__<P extends keyof this | string>(prop: P, func: Function): void;
    __defineGetter__<P extends PropertyKey>(prop: P, func: () => any): void;
    __defineSetter__<P extends keyof this | string>(prop: P, func: (val: any) => any): void;
    __defineSetter__<P extends PropertyKey>(prop: P, func: (val: any) => void): void;
    __lookupGetter__<P extends keyof this>(prop: P): (() => this[P]) | undefined;
    __lookupGetter__<P extends PropertyKey>(prop: P): (() => any) | undefined;
    __lookupSetter__<P extends keyof this>(prop: P): ((val: this[P]) => this[P]) | undefined;
    __lookupSetter__<P extends PropertyKey>(prop: P): ((val: any) => any) | undefined;
    get __proto__(): Object | null;
    set __proto__(prototype: Object | null);
}

